<?php
/**
 * Noto Sans Cyrillic Font Installer
 * ------------------------------------
 * Upload this file to your server root, then visit:
 *   https://whatchan.co.uk/install-fonts.php
 * It will create the font files and then delete itself.
 */

$base = __DIR__;
$fontDir = $base . '/wp-content/themes/' . get_active_theme() . '/fonts';

// Try a few likely locations
$candidates = [
    $base . '/bulgarian/fonts',
    $base . '/wp-content/uploads/bulgarian-fonts',
];

$fontDir = null;
foreach ($candidates as $c) {
    if (!file_exists($c)) @mkdir($c, 0755, true);
    if (is_writable($c)) { $fontDir = $c; break; }
}

if (!$fontDir) {
    die('Could not find or create a writable fonts directory. Try creating /bulgarian/fonts/ manually via cPanel.');
}

// Font files as base64
$fonts = [
    'noto-sans-cyrillic.woff2'        => '',
    'noto-sans-cyrillic-italic.woff2' => '',
];

$saved = [];
foreach ($fonts as $filename => $b64) {
    $path = $fontDir . '/' . $filename;
    file_put_contents($path, base64_decode($b64));
    $saved[] = $filename . ' (' . round(filesize($path)/1024, 1) . 'KB)';
}

// Work out the web URL for the font directory
$webRoot = (isset($_SERVER['HTTPS']) ? 'https' : 'http') . '://' . $_SERVER['HTTP_HOST'];
$relDir  = str_replace($base, '', $fontDir);
$fontUrl = $webRoot . str_replace(DIRECTORY_SEPARATOR, '/', $relDir);

// Build the CSS to put in the WordPress snippet
$css = "@font-face {
  font-family: 'Source Sans 3';
  font-style: normal;
  font-weight: 400 700;
  src: url('{$fontUrl}/noto-sans-cyrillic.woff2') format('woff2');
  unicode-range: U+0301, U+0400-045F, U+0490-0491, U+04B0-04B1, U+2116;
  font-display: swap;
}
@font-face {
  font-family: 'Source Sans 3';
  font-style: italic;
  font-weight: 400;
  src: url('{$fontUrl}/noto-sans-cyrillic-italic.woff2') format('woff2');
  unicode-range: U+0301, U+0400-045F, U+0490-0491, U+04B0-04B1, U+2116;
  font-display: swap;
}";

// Self-delete
@unlink(__FILE__);

?><!DOCTYPE html>
<html>
<head><title>Font Installer</title>
<style>body{font-family:sans-serif;max-width:700px;margin:40px auto;padding:20px;background:#f5f5f5}
.ok{background:#e8f5ee;border:1px solid #27ae60;border-radius:6px;padding:15px 20px;margin:10px 0}
pre{background:#1a1f4e;color:#fdf8f0;padding:16px;border-radius:6px;overflow-x:auto;font-size:13px}
</style></head>
<body>
<h2>✅ Noto Sans Cyrillic — Font Installer</h2>
<div class="ok">
<strong>Fonts saved to:</strong> <?= $fontDir ?><br>
<strong>Files:</strong> <?= implode(', ', $saved) ?>
</div>
<h3>Next step — update your WordPress snippet</h3>
<p>Go to <strong>Code Snippets → Bulgarian Cyrillic Font Fix</strong> and replace the content with this:</p>
<pre><?= htmlspecialchars('<style>' . "
" . $css . "
" . '</style>') ?></pre>
<p><em>This installer has deleted itself. The fonts are now on your server permanently.</em></p>
</body></html>